mapper.select:
select c1.id, u1.username, coalesce(u1.nickname,c1.nickname) as nickname, c1.content, coalesce(u1.avatar,c1.avatar) as avatar, c1.create_time, c1.is_admin_comment, c1.website, c1.parent_comment_id as parent_comment_id, coalesce(u2.nickname,c2.nickname) as parent_comment_nickname from comment as c1 left join user as u1 on c1.user_id=u1.id left join comment as c2 on c1.parent_comment_id=c2.id left join user as u2 on c2.user_id=u2.id where c1.page=#{page}
and c1.blog_id=#{blogId}
and c1.parent_comment_id=#{parentCommentId} and c1.is_published=true order by c1.create_time desc, c1.id desc

with recursive reply_ids (id) as ( select c.id from comment as c where c.page=#{page}
and c.blog_id=#{blogId}
and c.parent_comment_id in
#{rootCommentId}
and c.is_published=true union distinct select child.id from comment as child inner join reply_ids as ancestor on child.parent_comment_id=ancestor.id where child.page=#{page}
and child.blog_id=#{blogId}
and child.is_published=true limit #{replyLimit} ) select c1.id, u1.username, coalesce(u1.nickname,c1.nickname) as nickname, c1.content, coalesce(u1.avatar,c1.avatar) as avatar, c1.create_time, c1.is_admin_comment, c1.website, c1.parent_comment_id as parent_comment_id, coalesce(u2.nickname,c2.nickname) as parent_comment_nickname from reply_ids inner join comment as c1 on c1.id=reply_ids.id left join user as u1 on c1.user_id=u1.id left join comment as c2 on c1.parent_comment_id=c2.id left join user as u2 on c2.user_id=u2.id order by c1.id asc

select c.id, c.blog_id, c.user_id, u.username, coalesce(u.nickname, c.nickname) as nickname, c.content, coalesce(u.avatar, c.avatar) as avatar, c.create_time, c.website, c.is_published, c.is_admin_comment, c.parent_comment_id from comment as c left join user as u on c.user_id=u.id where c.page=0 and c.blog_id in
#{blogId}
order by c.blog_id, c.id

select count(*) from comment
where page=#{page}

    and is_published=#{isPublished}


    and blog_id=#{blogId}
